const BASE = 'https://mirador-villarrica-chatbot-pruebasn8ncub-6852s-projects.vercel.app/assets';

const CATALOGO = {
  volcan: [
    { url: `${BASE}/banner-volcan.jpg`, alt: 'Vista aérea del proyecto con Volcán Villarrica al fondo' },
  ],
  lago: [
    { url: `${BASE}/lagocolico.jpg`, alt: 'Lago Colico a 20 minutos del proyecto' },
    { url: `${BASE}/galeria1.jpg`, alt: 'Entorno natural hacia el lago' },
    { url: `${BASE}/galeria5-atardecer.jpg`, alt: 'Atardecer en Mirador de Villarrica' },
  ],
  bosque: [
    { url: `${BASE}/galeria3.jpg`, alt: 'Bosque nativo en Mirador de Villarrica' },
    { url: `${BASE}/imagen1.jpg`, alt: 'Bosque y accesos del proyecto' },
  ],
  atardecer: [
    { url: `${BASE}/galeria5-atardecer.jpg`, alt: 'Atardecer sobre el proyecto' },
  ],
  vista_general: [
    { url: `${BASE}/galeria6.jpg`, alt: 'Panorámica del terreno' },
    { url: `${BASE}/galeria7.jpg`, alt: 'Parcela con vista al entorno natural' },
    { url: `${BASE}/galeria2.jpg`, alt: 'Vista general del proyecto' },
  ],
};

const tema = ($json.tema || 'vista_general').toLowerCase();
const images = CATALOGO[tema] || CATALOGO.vista_general;

return [{ json: {
  type: 'gallery',
  images,
  count: images.length,
  tema_resuelto: CATALOGO[tema] ? tema : 'vista_general',
  tool_output_text: `Te comparto ${images.length} ${images.length === 1 ? 'foto' : 'fotos'} del tema "${tema}". ¿Quieres ver algo específico más?`,
} }];
